<?php
namespace App\Http\Controllers\Admin; use App\Http\Controllers\Controller; use App\Http\Requests\Admin\RoleRequest; use App\Models\{Role,Permission}; use App\Services\Admin\ActivityLogger;
class RoleController extends Controller { public function index(){return view('admin.roles.index',['roles'=>Role::with('permissions')->paginate(15)]);} public function create(){return view('admin.roles.form',['role'=>new Role,'permissions'=>Permission::all()]);} public function store(RoleRequest $r, ActivityLogger $l){$role=Role::create(['name'=>$r->name,'guard_name'=>'web']); $role->permissions()->sync($r->permissions??[]); $l->log('created','Created role '.$role->name,$role); return redirect()->route('admin.roles.index');} public function edit(Role $role){return view('admin.roles.form',['role'=>$role,'permissions'=>Permission::all()]);} public function update(RoleRequest $r, Role $role, ActivityLogger $l){$role->update(['name'=>$r->name]); $role->permissions()->sync($r->permissions??[]); $l->log('updated','Updated role '.$role->name,$role); return redirect()->route('admin.roles.index');} public function destroy(Role $role, ActivityLogger $l){$l->log('deleted','Deleted role '.$role->name,$role); $role->delete(); return back();} }
